function hexCharsToByteArrary(frame){
    const bytes = [];
    for(let i =0;i<frame.length;i+=2){
        const byte = parseInt(frame[i]+frame[i+1],16)
        bytes.push(byte);
    }
    return bytes;
}


// 将 2 字节转为整数
function readTwoByteToInt(bytes, offset) {
    const signal1 = bytes[offset]     // 读取第一个字节
    const signal2 = bytes[offset+1] // 读取第二个字节

    // 将 2 字节拼接为一个整数
    //let combinedSignal = (signal1 << 8) | signal2;//高位在前
    let combinedSignal = (signal2 << 8) | signal1;//低位在前
    if (combinedSignal > 0x7FFF) 
    {
       combinedSignal -= 0x10000;  // 如果大于32767，则减去65536，得到负数
    }
     act = combinedSignal/32768*16;

     if(act > 0)
     {
         act1 = act -0.9;
     }

     else if(act < 0)
     {
         act1 = act  + 0.9;
     }
    return act1;
}

// 通用函数：将 3 字节转为整数，处理空值
function SignalToInt(bytes, offset) {
    const byte1 = bytes[offset];        // 读取第一个字节
    const byte2 = bytes[offset+1];    // 读取第二个字节
    const byte3 = bytes[offset+2];    // 读取第三个字节

    // 将 3 字节拼接为一个整数
    let combinedSignal = (byte1 << 16) | (byte2 << 8) | byte3;//高位在前
    //let combinedSignal = (byte3 << 16) | (byte2 << 8) | byte1;//低位在前
    if (combinedSignal > 0x7FFFFF) 
    {
        combinedSignal -= 0x1000000;  // 如果大于8388607，则减去16777216，得到负数
    }
    act = combinedSignal / 8388608 * 2.5;

    return act;
}

// 将 2 字节转为整数（温度2）
function parseTemp2Byte(bytes, offset) {
    const high = bytes[offset];     // 读取第一个字节
    const low = bytes[offset+1]; // 读取第二个字节

    //

    // 将 2 字节拼接为一个整数
        //let combinedSignal = (signal1 << 8) | signal2;//高位在前
     //let combinedSignal = (low << 8) | high;
     let combinedSignal = (high << 8) | low;
     if (combinedSignal > 0x7FFF) 
     {
         combinedSignal += 1;   
         combinedSignal = -combinedSignal;  
     }
       act = combinedSignal * 0.0078125;

    return act;
}


function parse(frame) {

    //console.log("➡️ JS 解析函数开始执行！");
    //console.log("frame.length =", frame.length);
    //console.log("typeof frame =", typeof frame);
    //console.log("frame instanceof Array =", frame instanceof Array);

    //let act = 0;起始序列
    let offset_n = 10;

    length1 = 2132;
    length2 = 160;
    length3 = 160;
    length4 = 160;
    length5 = 1;
    length6 = 1;

    totalLength = length2 + length3 + length4

    let i2 = 0, i3 = 0, i4 = 0;

    const data = [];

    const bytes = hexCharsToByteArrary(frame);

    //console.log("📦 frame长度 =", frame.length);
    //console.log(bytes[2733], bytes[2734]);   // 输出十进制
    //console.log(bytes[2733].toString(16).padStart(2,'0'), bytes[2734].toString(16).padStart(2,'0')); // 输出十六进制


    for(let i=0;i<length1;i++)
    {
        // 读取 2 字节的整数
        const signal1 = readTwoByteToInt(bytes, offset_n); 
        data.push(signal1);
        offset_n += 2; 
    }

    for(let i = 0; i<totalLength;i++)
    {
        const channel = i%3;

        if(channel === 0 && i2<length2)
        {
            const signal2 = SignalToInt(bytes, offset_n);
            data.push(signal2);
            offset_n += 3;  
            i2++;
        }

        else if(channel === 1 && i3<length3)
        {
            const signal3 = SignalToInt(bytes, offset_n);
            data.push(signal3);
            offset_n += 3;  
            i3++;
        }

        else if(channel === 2 && i4<length4)
        {
            const signal4 = SignalToInt(bytes, offset_n);
            data.push(signal4);
            offset_n += 3;  
            i4++;
        }

        else {
        // 如果该通道已读完，跳过到下一个非空通道
            if (i2 < length2) {
                const signal2 = SignalToInt(bytes, offset_n);
                data.push(signal2);
                offset_n += 3;
                i2++;
            } else if (i3 < length3) {
                const signal3 = SignalToInt(bytes, offset_n);
                data.push(signal3);
                offset_n += 3;
                i3++;
            } else if (i4 < length4) {
                const signal4 = SignalToInt(bytes, offset_n);
                data.push(signal4);
                offset_n += 3;
                i4++;
            }
        }

    }

    for(let i=0;i<length5;i++)
    {
        // 读取 3 字节的整数
        const signal5 =  SignalToInt(bytes, offset_n); 
        data.push(signal5);
        offset_n += 3; 
    }

    for(let i=0;i<length6;i++)
    {
        // 读取 2 字节的整数
        //console.log("解析温度2起点 =", offset_n);
        const signal6 =  parseTemp2Byte(bytes, offset_n); 
        data.push(signal6);
        offset_n += 2; 
    }

    return data;
}
